// Student no longer exists after deletion
pm.test("Student no longer exists after deletion", function () {
    pm.sendRequest({
        url: pm.variables.get("base_url") + "/api/students/" + student_id,
        method: "GET"
    }, function (err, res) {
        pm.expect(res).to.have.status(404);
    });
});

// Response is JSON
pm.test("Response is JSON", function () {
    pm.response.to.have.header("Content-Type", "application/json; charset=utf-8");
});

// Each student has name, major, gpa, and id
// gpa can be null (e.g., a student has not completed any courses yet and does not have a GPA)
pm.test("Each student has name, major, gpa, and id", function () {
    const data = pm.response.json();
    data.forEach(student => {
        pm.expect(student).to.have.property("name");
        pm.expect(student).to.have.property("major");
        pm.expect(student).to.have.property("gpa");
        pm.expect(student).to.have.property("id");
        if (student.gpa !== null) {
            pm.expect(student.gpa).to.be.a("number");
            pm.expect(student.gpa).to.be.at.least(0);
            pm.expect(student.gpa).to.be.at.most(4.0);
        }
    });
});

// Response time is acceptable
pm.test("Response time is below 2000ms", function () {
    pm.expect(pm.response.responseTime).to.be.below(2000);
});

// Status is 200
pm.test("Status code is 200", function () {
    pm.response.to.have.status(200);
});

// Response is JSON
pm.test("Response is JSON", function () {
    pm.response.to.have.header("Content-Type", "application/json; charset=utf-8");
});

// Response is an array
pm.test("Response is an array", function () {
    const data = pm.response.json();
    pm.expect(Array.isArray(data)).to.be.true;
});

// Each course has required fields
pm.test("Each course has name, maxSize, instructor, and room", function () {
    const data = pm.response.json();
    data.forEach(course => {
        pm.expect(course).to.have.property("id");
        pm.expect(course).to.have.property("name");
        pm.expect(course).to.have.property("maxSize");
        pm.expect(course).to.have.property("instructor");
        pm.expect(course).to.have.property("room");
    });
});

// Each course roster is a set
pm.test("Each course has a roster that is a set", function () {
    const data = pm.response.json();
    data.forEach(course => {
        pm.expect(course).to.have.property("roster");
        pm.expect(Array.isArray(course.roster)).to.be.true;
    });
});

// Enrollment does not exceed maxSize
pm.test("Enrollment does not exceed maxSize", function () {
    const data = pm.response.json();
    data.forEach(course => {
        pm.expect(course.roster.length).to.be.at.most(course.maxSize);
    });
});

// Response time is acceptable
pm.test("Response time is below 2000ms", function () {
    pm.expect(pm.response.responseTime).to.be.below(2000);
});
